const request = $input.first().json || {};
const headers = request.headers || {};
const incomingKey = String(headers['x-crm-key'] || headers['X-Crm-Key'] || headers['X-CRM-KEY'] || '').trim();
const expectedKey = String($env.CRM_API_KEY || '').trim();
if (!expectedKey || incomingKey !== expectedKey) {
  return [{ json: { ok: false, success: false, message: 'unauthorized' } }];
}
const body = request.body || request || {};
const action = body.action === 'cancel' ? 'cancel' : 'upsert';
const invoiceId = Number(body.invoiceId || 0);
return [{ json: {
  ok: true,
  success: true,
  action,
  invoiceId,
  scheduledFor: action === 'cancel' ? null : (body.reminderDate || body.dueDate || null),
  message: action === 'cancel' ? 'cancel accepted' : 'reminder accepted'
} }];

const response = $input.first().json || {};
const invoices = response.data?.list || response.list || [];
const staticData = $getWorkflowStaticData('global');
staticData.sentPaymentReminderKeys = staticData.sentPaymentReminderKeys || {};

function pad(value) { return String(value).padStart(2, '0'); }
function todayKst() {
  const now = new Date();
  const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
  return `${kst.getUTCFullYear()}-${pad(kst.getUTCMonth() + 1)}-${pad(kst.getUTCDate())}`;
}
function shiftDate(date, days) {
  const match = String(date || '').match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return '';
  const d = new Date(Date.UTC(Number(match[1]), Number(match[2]) - 1, Number(match[3])));
  d.setUTCDate(d.getUTCDate() + days);
  return `${d.getUTCFullYear()}-${pad(d.getUTCMonth() + 1)}-${pad(d.getUTCDate())}`;
}
function parseIntSafe(value) {
  const n = Number(String(value ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? Math.max(0, Math.trunc(n)) : 0;
}
function htmlEscape(value) {
  return String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function parseInvoiceMeta(memo) {
  const lines = String(memo || '').replace(/\r\n/g, '\n').split('\n');
  const line = lines.map((entry) => entry.trim()).find((entry) => entry.startsWith('[ACCOUNTING_INVOICE_META]'));
  if (!line) return {};
  try { return JSON.parse(line.slice('[ACCOUNTING_INVOICE_META]'.length).trim()) || {}; } catch (error) { return {}; }
}
function remainingAmount(invoice, meta) {
  return Math.max(0, parseIntSafe(invoice.total_amount) - parseIntSafe(invoice.paid_amount) - parseIntSafe(meta.depositUsedAmount));
}

const today = todayKst();
const targets = [];

for (const invoice of invoices) {
  const meta = parseInvoiceMeta(invoice.memo);
  const reminder = meta.paymentReminder || {};
  const dueDate = String(reminder.dueDate || '').slice(0, 10);
  if (!reminder.enabled || !/^\d{4}-\d{2}-\d{2}$/.test(dueDate)) continue;
  const amount = parseIntSafe(reminder.amount) || remainingAmount(invoice, meta);
  const remaining = remainingAmount(invoice, meta);
  if (amount <= 0 || remaining <= 0 || invoice.payment_status === 'paid') continue;
  const leadDays = Math.max(0, Math.min(30, parseIntSafe(reminder.leadDays)));
  const reminderDate = shiftDate(dueDate, -leadDays);
  if (!reminderDate || reminderDate > today) continue;

  const key = `${invoice.Id}:${dueDate}:${amount}`;
  if (staticData.sentPaymentReminderKeys[key]) continue;
  staticData.sentPaymentReminderKeys[key] = today;

  const customerName = invoice.customer_name || '거래처 미지정';
  const invoiceNo = invoice.invoice_no || '-';
  const internalMemo = meta.internalMemo ? String(meta.internalMemo).trim() : '';
  const crmUrl = `https://crm.pressco21.com/invoices?edit=${invoice.Id}`;
  const overdueLabel = dueDate < today ? `기한 초과 ${dueDate}` : '오늘 납부 예정';

  let text = `<b>대금 납부 리마인더</b>\n\n`;
  text += `${htmlEscape(overdueLabel)}\n`;
  text += `거래처: <b>${htmlEscape(customerName)}</b>\n`;
  text += `예정 금액: <b>${amount.toLocaleString('ko-KR')}원</b>\n`;
  text += `현재 미수: ${remaining.toLocaleString('ko-KR')}원\n`;
  text += `명세표: ${htmlEscape(invoiceNo)}\n`;
  if (internalMemo) text += `\n내부 메모:\n${htmlEscape(internalMemo).slice(0, 700)}\n`;
  text += `\nCRM: ${crmUrl}`;

  targets.push({ json: {
    shouldSend: true,
    text,
    chatId: $env.PRESSCO21_OPS_CHAT_ID || '-1003980879769',
    threadId: $env.PRESSCO21_OPS_PAYMENT_THREAD_ID || '4',
    invoiceId: invoice.Id,
    dueDate,
    amount
  } });
}

if (targets.length === 0) {
  return [{ json: { shouldSend: false, count: 0, today } }];
}
return targets;
